async function loadAll(table:string,select='*'){const db=getSupabase();if(!db)throw new Error('Supabase تنظیم نشده است');const out:any[]=[];for(let from=0;;from+=1000){const{data,error}=await db.from(table).select(select).range(from,from+999);if(error)throw error;const batch=data||[];out.push(...batch);if(batch.length<1000)break}return out}
async function upsertChunks(table:string,rows:any[],onConflict='id',size=400){const db=getSupabase();if(!db)throw new Error('Supabase تنظیم نشده است');for(let i=0;i<rows.length;i+=size){const{error}=await db.from(table).upsert(rows.slice(i,i+size),{onConflict});if(error)throw error}}
function downloadWorkbook(wb:XLSX.WorkBook,name:string){XLSX.writeFile(wb,name)}

export function ProviderCoverageCenter({master=[],rules=[]}:{master:any[];rules:ProviderRule[]}){
  const [rows,setRows]=useState<any[]>([]),[busy,setBusy]=useState(true),[q,setQ]=useState(''),[provider,setProvider]=useState('all'),[statusFilter,setStatusFilter]=useState('all'),[defaultProvider,setDefaultProvider]=useState('IHO Provider'),[msg,setMsg]=useState('');
  const fileRef=useRef<HTMLInputElement|null>(null);
  async function load(){setBusy(true);try{setRows(await loadAll('ihos_provider_coverage','*'));setMsg('داده‌های Online Maximizer دریافت شد')}catch(e:any){setMsg(`دریافت داده ناموفق بود: ${e.message}`)}finally{setBusy(false)}}
  useEffect(()=>{void load()},[]);
  const providers=useMemo(()=>[...new Set([...rules.map(r=>r.name),...rows.map(r=>r.provider)])].filter(Boolean),[rules,rows]);
  const ruleMap=useMemo(()=>new Map(rules.map(r=>[norm(r.name),r])),[rules]);
  const hotelKey=(r:any)=>String(r.hotel_id||r.hotel_code||norm(r.hotel_title));
  const stats=useMemo(()=>providers.map(name=>{const list=rows.filter(r=>norm(r.provider)===norm(name)&&r.active!==false),eligible=new Set(list.map(hotelKey)).size,live=new Set(list.filter(r=>r.rate_live||r.capacity_live).map(hotelKey)).size,full=new Set(list.filter(r=>r.rate_live&&r.capacity_live).map(hotelKey)).size,blocked=list.filter(r=>r.connection_status==='blocked').length,manual=list.filter(r=>r.delivery_mode==='manual').length,rule=ruleMap.get(norm(name));return{name,eligible,live,full,blocked,manual,pct:eligible?Math.round(live/eligible*100):0,api:rule?.rateApi&&rule?.capacityApi?'کامل':rule?.capacityApi?'ظرفیت':rule?.rateApi?'نرخ':'دستی'}}).sort((a,b)=>(Number(ruleMap.get(norm(a.name))?.priority||99)-Number(ruleMap.get(norm(b.name))?.priority||99))||b.eligible-a.eligible),[providers,rows,ruleMap]);
  const overall=useMemo(()=>{const active=rows.filter(r=>r.active!==false),groups=new Map<string,any[]>();active.forEach(r=>groups.set(hotelKey(r),[...(groups.get(hotelKey(r))||[]),r]));const values=[...groups.values()];return{eligible:values.length,rate:values.filter(x=>x.some(r=>r.rate_live)).length,capacity:values.filter(x=>x.some(r=>r.capacity_live)).length,full:values.filter(x=>x.some(r=>r.rate_live)&&x.some(r=>r.capacity_live)).length,multi:values.filter(x=>new Set(x.map(r=>norm(r.provider))).size>1).length,multiLive:values.filter(x=>new Set(x.filter(r=>r.rate_live||r.capacity_live).map(r=>norm(r.provider))).size>1).length}},[rows]);
  const filtered=useMemo(()=>rows.filter(r=>(provider==='all'||norm(r.provider)===norm(provider))&&(statusFilter==='all'||(r.connection_status||'eligible')===statusFilter)&&(!q.trim()||norm(`${r.hotel_title} ${r.hotel_code} ${r.city} ${r.provider} ${r.blocker_reason}`).includes(norm(q)))),[rows,provider,statusFilter,q]);
  const candidates=useMemo(()=>{const byCode=new Map<string,any[]>();rows.filter(r=>r.active!==false).forEach(r=>{const key=String(r.hotel_code||'').trim();if(key)byCode.set(key,[...(byCode.get(key)||[]),r])});return master.filter(isSellable).map(h=>{const list=byCode.get(String(h.hotel_code||'').trim())||[],ranked=list.map(c=>{const rule=ruleMap.get(norm(c.provider));const score=(c.coverage_type==='نرخ و ظرفیت'?100:c.coverage_type==='فقط ظرفیت'?70:45)+(rule?.rateApi?20:0)+(rule?.capacityApi?25:0)+(c.delivery_mode==='api'?25:c.delivery_mode==='hybrid'?12:0)+Math.max(0,20-Number(c.priority||rule?.priority||20));return{...c,score}}).sort((a,b)=>b.score-a.score);return{hotel:h,best:ranked[0],count:ranked.length}}).filter(x=>x.count>0&&norm(x.best?.provider)!==norm(x.hotel.provider)).sort((a,b)=>(b.best?.score||0)-(a.best?.score||0))},[master,rows,ruleMap]);
  async function updateRow(row:any,patch:any){const next={...row,...patch,updated_at:nowIso(),live_at:(patch.rate_live||patch.capacity_live)&&!row.live_at?nowIso():row.live_at};setRows(current=>current.map(x=>x.id===row.id?next:x));try{await upsertChunks('ihos_provider_coverage',[next]);setMsg(`${row.hotel_title} به‌روزرسانی شد`)}catch(e:any){setRows(current=>current.map(x=>x.id===row.id?row:x));setMsg(`ذخیره ناموفق بود: ${e.message}`)}}
  async function markBlocked(row:any){const reason=prompt('دلیل منتقل یا Live نشدن هتل چیست؟',row.blocker_reason||'')?.trim();if(reason===undefined)return;const nextAction=prompt('اقدام بعدی چیست؟',row.next_action||'')?.trim()||'';const owner=prompt('مسئول پیگیری چه کسی است؟',row.owner_name||'')?.trim()||'';await updateRow(row,{connection_status:'blocked',blocker_reason:reason,next_action:nextAction,owner_name:owner})}
  async function parse(file:File){setBusy(true);setMsg(`در حال ورود نام و شناسه هتل‌های ${defaultProvider}...`);try{const wb=XLSX.read(await file.arrayBuffer(),{type:'array',cellDates:false}),ws=wb.Sheets[wb.SheetNames[0]],data=XLSX.utils.sheet_to_json(ws,{defval:null,raw:false}) as any[];if(!data.length)throw new Error('فایل خالی است');const rule=ruleMap.get(norm(defaultProvider)),missing:string[]=[];const mapped=data.map((r:any)=>{const suppliedId=text(r,['ایدی هتل','آیدی هتل','شناسه هتل','hotel_id','hotel id','id']),code=text(r,['کد هتل','hotel_code','hotel code','کدهتل']),title=text(r,['نام هتل','hotel_title','hotel name','hotel']),hotel=master.find(h=>(suppliedId&&String(h.id)===suppliedId)||(code&&String(h.hotel_code||'')===code)||(title&&norm(h.title)===norm(title)));if(!suppliedId&&!code&&!title)return null;if(!hotel&&!suppliedId){missing.push(title||code);return null}const token=String(hotel?.id||suppliedId||code||norm(title)).replace(/\s+/g,'-'),id=`coverage-${norm(defaultProvider).replace(/\s+/g,'-')}-${token}`,existing=rows.find(x=>x.id===id);return{...existing,id,provider:defaultProvider,hotel_id:hotel?.id||suppliedId||null,hotel_code:hotel?.hotel_code||code||null,hotel_title:hotel?.title||title||'هتل بدون نام',city:hotel?.city||existing?.city||'',coverage_type:existing?.coverage_type||(rule?.rateApi&&rule?.capacityApi?'نرخ و ظرفیت':rule?.capacityApi?'فقط ظرفیت':rule?.rateApi?'فقط نرخ':'نرخ و ظرفیت'),delivery_mode:existing?.delivery_mode||(rule?.rateApi||rule?.capacityApi?'api':'manual'),connection_status:existing?.connection_status||'eligible',priority:existing?.priority||Number(rule?.priority)||50,rate_live:existing?.rate_live||false,capacity_live:existing?.capacity_live||false,active:true,source_name:file.name,created_at:existing?.created_at||nowIso(),updated_at:nowIso()}}).filter(Boolean) as any[];if(!mapped.length)throw new Error(`هیچ هتلی قابل ورود نبود${missing.length?`؛ نمونه نام‌های پیدا نشده: ${missing.slice(0,3).join('، ')}`:''}`);const unique=[...new Map(mapped.map(row=>[row.id,row])).values()];const duplicateCount=mapped.length-unique.length;await upsertChunks('ihos_provider_coverage',unique);setProvider(defaultProvider);setMsg(`${fa(unique.length)} هتل یکتا برای ${defaultProvider} اضافه شد${duplicateCount?` · ${fa(duplicateCount)} ردیف تکراری ادغام شد`:''}${missing.length?` · ${fa(missing.length)} ردیف تطبیق نداشت`:''}. تنظیمات قبلی حفظ شدند.`);await load()}catch(e:any){setMsg(`خطا: ${e.message}`)}finally{setBusy(false)}}
  function template(){const data=master.map(h=>({'ایدی هتل':h.id||'','نام هتل':h.title||''}));const wb=XLSX.utils.book_new();XLSX.utils.book_append_sheet(wb,XLSX.utils.json_to_sheet(data),'هتل‌های Provider');XLSX.utils.book_append_sheet(wb,XLSX.utils.aoa_to_sheet([['راهنما'],[`این فایل برای ${defaultProvider} است.`],['فقط شناسه و نام هتل را نگه دارید؛ تمام تنظیمات دیگر داخل اپ انجام می‌شود.']]),'راهنما');downloadWorkbook(wb,`IHO-${defaultProvider}-Hotels.xlsx`)}
  async function remove(id:string){if(!confirm('این اتصال هتل–Provider حذف شود؟'))return;const db=getSupabase();if(db)await db.from('ihos_provider_coverage').delete().eq('id',id);setRows(rows.filter(r=>r.id!==id))}
  return <div className="v17Module providerCoverageV17 onlineMaximizerV21">
    <div className="v17Hero"><div><span>ONLINE MAXIMIZER</span><h2>حداکثرسازی آنلاین‌سازی نرخ و ظرفیت</h2><p>هتل‌های هر Provider را وارد کن، اولویت و مانع را ثبت کن و Live نرخ و ظرفیت را بدون دوباره‌شماری هتل‌های چند‌Providerی بسنج.</p></div><div className="v17HeroActions"><button className="btn ghost" onClick={template}><Download/> قالب {defaultProvider}</button><select value={defaultProvider} onChange={e=>setDefaultProvider(e.target.value)}>{providers.map(p=><option key={p}>{p}</option>)}</select><button className="btn primary" onClick={()=>fileRef.current?.click()}><Upload/> آپلود هتل‌های Provider</button><input ref={fileRef} hidden type="file" accept=".xlsx,.xls,.csv" onClick={e=>{e.currentTarget.value=''}} onChange={e=>{const f=e.target.files?.[0];if(f)void parse(f)}}/></div></div>
    {msg&&<div className="v17Notice" role="status" aria-live="polite">{busy&&<RefreshCcw className="spin"/>}{msg}</div>}
    <div className="onlineKpisV21"><article><b>{fa(overall.eligible)}</b><span>هتل یکتای قابل تأمین</span></article><article><b>{overall.eligible?fa(Math.round(overall.rate/overall.eligible*100)):0}٪</b><span>نرخ Live</span></article><article><b>{overall.eligible?fa(Math.round(overall.capacity/overall.eligible*100)):0}٪</b><span>ظرفیت Live</span></article><article><b>{overall.eligible?fa(Math.round(overall.full/overall.eligible*100)):0}٪</b><span>کاملاً آنلاین</span></article><article><b>{fa(overall.multi)}</b><span>چند‌Providerی</span></article><article><b>{fa(overall.multiLive)}</b><span>Live روی چند Provider</span></article></div>
    <div className="providerCardsV21">{stats.map(s=><button key={s.name} className={provider===s.name?'selected':''} onClick={()=>{setProvider(provider===s.name?'all':s.name);setDefaultProvider(s.name)}}><header><span><Building2/><b>{s.name}</b></span><strong>{fa(s.pct)}٪</strong></header><div className="providerProgressV21"><i style={{width:`${s.pct}%`}}/></div><p>{fa(s.live)} Live از {fa(s.eligible)} قابل تأمین</p><footer><span>{fa(s.full)} کامل</span><span>{fa(s.manual)} دستی</span><span>{fa(s.blocked)} مانع</span></footer></button>)}</div>
    <div className="v17Split"><section className="v17Panel"><header><div><h3>{provider==='all'?'همه اتصال‌های هتل–Provider':`مدیریت هتل‌های ${provider}`}</h3><p>{fa(filtered.length)} اتصال</p></div><button className="iconBtn" aria-label="بارگذاری مجدد" onClick={load}><RefreshCcw/></button></header><div className="v17Toolbar"><div className="v17Search"><Search/><input value={q} onChange={e=>setQ(e.target.value)} placeholder="هتل، کد، شهر یا دلیل مانع..."/></div><select value={statusFilter} onChange={e=>setStatusFilter(e.target.value)}><option value="all">همه وضعیت‌ها</option><option value="eligible">قابل تأمین</option><option value="queued">در صف</option><option value="connecting">در حال اتصال</option><option value="testing">تست</option><option value="live">Live</option><option value="blocked">مسدود</option><option value="rejected">ردشده</option></select></div><div className="providerHotelListV21">{filtered.slice(0,500).map(r=><article key={r.id}><div className="providerHotelIdentityV21"><b>{r.hotel_title}</b><small>{r.hotel_code||'بدون کد'} · {r.city||'بدون شهر'} · {r.provider}</small>{r.blocker_reason&&<em>{r.blocker_reason}</em>}</div><select value={r.delivery_mode||'api'} onChange={e=>updateRow(r,{delivery_mode:e.target.value})}><option value="api">API</option><option value="manual">دستی</option><option value="hybrid">ترکیبی</option></select><select value={r.connection_status||'eligible'} onChange={e=>updateRow(r,{connection_status:e.target.value})}><option value="eligible">قابل تأمین</option><option value="queued">در صف</option><option value="connecting">اتصال</option><option value="testing">تست</option><option value="live">Live</option><option value="blocked">مسدود</option><option value="rejected">ردشده</option></select><label><input type="checkbox" checked={!!r.rate_live} onChange={e=>updateRow(r,{rate_live:e.target.checked,connection_status:e.target.checked&&r.capacity_live?'live':r.connection_status})}/> نرخ Live</label><label><input type="checkbox" checked={!!r.capacity_live} onChange={e=>updateRow(r,{capacity_live:e.target.checked,connection_status:e.target.checked&&r.rate_live?'live':r.connection_status})}/> ظرفیت Live</label><input className="priorityInputV21" aria-label="اولویت" type="number" min="1" max="999" value={r.priority||50} onChange={e=>updateRow(r,{priority:+e.target.value})}/><button className="btn ghost" onClick={()=>markBlocked(r)}>ثبت مانع</button><button className="iconBtn dangerBtn" onClick={()=>remove(r.id)}><Trash2/></button></article>)}</div></section>
      <section className="v17Panel"><header><div><h3>پیشنهاد اولویت مهاجرت</h3><p>پوشش + API + اولویت Provider</p></div><Sparkles/></header><div className="v17SuggestionList">{candidates.slice(0,100).map(x=><article key={x.hotel.id}><div><b>{x.hotel.title}</b><small>{x.hotel.provider||'بدون Provider'} · {x.count} گزینه</small></div><ArrowLeft/><div><b>{x.best.provider}</b><small>{x.best.coverage_type} · امتیاز {x.best.score}</small></div></article>)}{!candidates.length&&<div className="v17Empty"><CheckCircle2/><h3>پیشنهاد جدیدی وجود ندارد</h3><p>فهرست هتل‌های Providerها را وارد کن.</p></div>}</div></section></div>
  </div>
}

export function ReviewCenterV17({tasks=[],saveTask,openTask}:any){
  const waiting=tasks.filter((t:any)=>['ارسال برای تایید','در انتظار تایید','بازبینی'].includes(t.status));
  const changes=tasks.filter((t:any)=>t.status==='نیازمند اصلاح');
  const approved=tasks.filter((t:any)=>['تایید شده','بسته شده'].includes(t.status)).slice(0,30);
  async function update(t:any,status:string){const note=prompt(status==='نیازمند اصلاح'?'دلیل یا توضیح اصلاح را بنویس':'یادداشت تایید (اختیاری)')||'';await saveTask({...t,status,pinned_note:note?`${t.pinned_note||''}\n[Review] ${note}`.trim():t.pinned_note,updated_at:nowIso()})}
  return <div className="v17Module"><div className="v17Hero"><div><span>QUALITY GATE</span><h2>مرکز تأیید و کنترل کیفیت</h2><p>تسک‌هایی که کارشناس برای پایان کار ارسال می‌کند، پیش از بسته‌شدن توسط مدیر بازبینی، تایید یا برای اصلاح برگردانده می‌شوند.</p></div><div className="v17ReviewFlow"><span>اجرای کار</span><i/><span>ارسال برای تأیید</span><i/><span>بازبینی مدیر</span><i/><span>بسته‌شدن</span></div></div><div className="v17ReviewGrid"><ReviewLane title="در انتظار بازبینی" rows={waiting} openTask={openTask} actions={(t:any)=><><button className="btn ghost" onClick={()=>update(t,'نیازمند اصلاح')}>نیازمند اصلاح</button><button className="btn primary" onClick={()=>update(t,'تایید شده')}><Check/> تأیید</button></>}/><ReviewLane title="برگشتی برای اصلاح" rows={changes} openTask={openTask}/><ReviewLane title="تأییدشده اخیر" rows={approved} openTask={openTask}/></div></div>
}
function ReviewLane({title,rows,openTask,actions}:any){return <section className="v17ReviewLane"><header><h3>{title}</h3><b>{fa(rows.length)}</b></header>{rows.map((t:any)=><article key={t.id}><div><b>{t.title}</b><small>{t.hotel_title||'بدون هتل'} · {t.assigned_name||'بدون مسئول'}</small></div><button className="btn ghost" onClick={()=>openTask(t)}>جزئیات</button>{actions?.(t)}</article>)}{!rows.length&&<div className="v17Empty"><ShieldCheck/><p>موردی در این مرحله نیست.</p></div>}</section>}

export function SlaCenterV17({tasks=[],categories=[]}:any){
  const [rules,setRules]=useState<any[]>([]),[editing,setEditing]=useState<any>({task_type:'',category:'',priority:'همه',sla_hours:24,warning_hours:4,active:true}),[busy,setBusy]=useState(true);
  async function load(){setBusy(true);try{setRules(await loadAll('ihos_sla_rules','*'))}finally{setBusy(false)}}useEffect(()=>{void load()},[]);
  async function save(){if(!editing.task_type.trim())return;const row={...editing,id:editing.id||uid(),updated_at:nowIso(),created_at:editing.created_at||nowIso()};await upsertChunks('ihos_sla_rules',[row]);setEditing({task_type:'',category:'',priority:'همه',sla_hours:24,warning_hours:4,active:true});await load()}
  async function remove(id:string){const db=getSupabase();if(db)await db.from('ihos_sla_rules').delete().eq('id',id);setRules(rules.filter(r=>r.id!==id))}
  const breaches=useMemo(()=>tasks.filter((t:any)=>{const rule=rules.find(r=>r.active!==false&&(r.category===t.category||r.task_type===t.category||r.task_type===t.title));if(!rule||!t.created_at||['انجام شد','بسته شده','تایید شده'].includes(t.status))return false;return Date.now()>new Date(t.created_at).getTime()+Number(rule.sla_hours||0)*3600000}),[tasks,rules]);
  return <div className="v17Module"><div className="v17Hero"><div><span>SERVICE LEVEL MANAGEMENT</span><h2>SLA و زمان استاندارد قابل تنظیم</h2><p>برای هر نوع یا دسته تسک، زمان پاسخ، هشدار و سطح اولویت را تعریف کن.</p></div><div className="v17HeroMetric"><Clock3/><b>{fa(breaches.length)}</b><span>تسک خارج از SLA</span></div></div><div className="v17Split"><section className="v17Panel"><header><h3>تعریف قانون جدید</h3><Settings2/></header><div className="v17FormGrid"><label>نوع تسک<input value={editing.task_type} onChange={e=>setEditing({...editing,task_type:e.target.value})} placeholder="مثلاً دریافت ظرفیت"/></label><label>دسته‌بندی<select value={editing.category||''} onChange={e=>setEditing({...editing,category:e.target.value})}><option value="">همه دسته‌ها</option>{categories.map((c:string)=><option key={c}>{c}</option>)}</select></label><label>اولویت<select value={editing.priority} onChange={e=>setEditing({...editing,priority:e.target.value})}><option>همه</option><option>فوری</option><option>بالا</option><option>متوسط</option><option>پایین</option></select></label><label>زمان استاندارد (ساعت)<input type="number" min="1" inputMode="numeric" value={editing.sla_hours} onChange={e=>setEditing({...editing,sla_hours:+e.target.value})}/></label><label>هشدار قبل از پایان (ساعت)<input type="number" min="0" inputMode="numeric" value={editing.warning_hours} onChange={e=>setEditing({...editing,warning_hours:+e.target.value})}/></label><label className="v17Check"><input type="checkbox" checked={editing.active} onChange={e=>setEditing({...editing,active:e.target.checked})}/> فعال</label></div><button className="btn primary" onClick={save}><Check/> ذخیره قانون SLA</button></section><section className="v17Panel"><header><div><h3>قوانین فعلی</h3><p>{fa(rules.length)} قانون</p></div><RefreshCcw className={busy?'spin':''} aria-label={busy?'در حال بارگذاری قوانین':'قوانین بارگذاری شدند'}/></header><div className="v17RuleList">{rules.map(r=><article key={r.id}><div><b>{r.task_type}</b><small>{r.category||'همه دسته‌ها'} · اولویت {r.priority||'همه'}</small></div><span>{r.sla_hours} ساعت</span><button className="iconBtn" aria-label={`ویرایش قانون ${r.task_type}`} onClick={()=>setEditing(r)}><Edit3/></button><button className="iconBtn dangerBtn" aria-label={`حذف قانون ${r.task_type}`} onClick={()=>remove(r.id)}><Trash2/></button></article>)}</div></section></div><section className="v17Panel"><header><h3>تسک‌های خارج از SLA</h3><AlarmClock/></header><div className="v17DataTable">{breaches.slice(0,100).map((t:any)=><article key={t.id}><div><b>{t.title}</b><small>{t.hotel_title||'بدون هتل'}</small></div><span>{t.assigned_name||'بدون مسئول'}</span><span className="v17Danger">{t.status}</span></article>)}</div></section></div>
}

export function MessageCenterV17({me,users=[],hotels=[]}:any){
  const initialChannel=me.team?{type:'team',id:me.team}:{type:'all',id:'all'};
  const [messages,setMessages]=useState<any[]>([]),[body,setBody]=useState(''),[channel,setChannel]=useState<any>(initialChannel),[hotelId,setHotelId]=useState(''),[query,setQuery]=useState(''),[replyTo,setReplyTo]=useState<any>(null),[important,setImportant]=useState(false),[busy,setBusy]=useState(false),[notice,setNotice]=useState('');
  const bottomRef=useRef<HTMLDivElement|null>(null);
  async function load(){try{setMessages((await loadAll('ihos_messages','*')).sort((a,b)=>String(a.created_at).localeCompare(String(b.created_at))));setNotice('')}catch(e:any){setNotice(`دریافت پیام‌ها ناموفق بود: ${e.message}`)}}
  useEffect(()=>{void load();const db=getSupabase();const ch=db?.channel('ihos-msg-v17').on('postgres_changes',{event:'*',schema:'public',table:'ihos_messages'},()=>load()).subscribe();return()=>{if(db&&ch)db.removeChannel(ch)}},[]);
  const activeUsers=useMemo(()=>users.filter((u:any)=>u.id!==me.id&&u.is_active),[users,me.id]);
  const accessible=useMemo(()=>messages.filter(m=>m.recipient_type==='all'||m.sender_id===me.id||(m.recipient_type==='user'&&m.recipient_id===me.id)||(m.recipient_type==='team'&&m.recipient_id===me.team)),[messages,me]);
  const visible=useMemo(()=>accessible.filter(m=>channel.type==='all'?m.recipient_type==='all':channel.type==='team'?m.recipient_type==='team'&&m.recipient_id===channel.id:m.recipient_type==='user'&&((m.sender_id===me.id&&m.recipient_id===channel.id)||(m.sender_id===channel.id&&m.recipient_id===me.id))).filter(m=>!query.trim()||norm(`${m.body} ${m.sender_name} ${m.hotel_title}`).includes(norm(query))),[accessible,channel,me.id,query]);
  const target=channel.type==='user'?activeUsers.find((u:any)=>u.id===channel.id):null;
  const channelTitle=channel.type==='all'?'کل سازمان':channel.type==='team'?channel.id||'تیم من':target?.full_name||'پیام مستقیم';
  const parentMap=useMemo(()=>new Map(messages.map(m=>[m.id,m])),[messages]);
  useEffect(()=>{bottomRef.current?.scrollIntoView({behavior:'smooth'})},[visible.length,channel.type,channel.id]);
  function lastFor(type:string,id:string){return [...accessible].reverse().find(m=>type==='all'?m.recipient_type==='all':type==='team'?m.recipient_type==='team'&&m.recipient_id===id:m.recipient_type==='user'&&((m.sender_id===me.id&&m.recipient_id===id)||(m.sender_id===id&&m.recipient_id===me.id)))}
  async function send(){
    if(!body.trim()||busy)return;if(channel.type==='user'&&!target){setNotice('ابتدا مخاطب پیام مستقیم را انتخاب کنید.');return}
    const hotel=hotels.find((h:any)=>h.id===hotelId);const row={id:uid(),sender_id:me.id,sender_name:me.full_name,recipient_type:channel.type,recipient_id:channel.type==='all'?null:channel.id,recipient_name:channelTitle,hotel_id:hotelId||null,hotel_title:hotel?.title||null,body:body.trim(),parent_id:replyTo?.id||null,is_important:important,created_at:nowIso()};
    setBusy(true);setMessages(list=>[...list,row]);setBody('');setReplyTo(null);setImportant(false);setNotice('');
    try{
      await upsertChunks('ihos_messages',[row]);
      const recipients=channel.type==='user'?activeUsers.filter((u:any)=>u.id===channel.id):channel.type==='team'?users.filter((u:any)=>u.is_active&&u.id!==me.id&&u.team===channel.id):users.filter((u:any)=>u.is_active&&u.id!==me.id);
      const notifications=recipients.map((user:any)=>({id:`message-notification-${row.id}-${user.id}`,title:`پیام جدید از ${me.full_name}`,body:row.body.slice(0,180),user_id:user.id,is_read:false,entity_type:'message',entity_id:row.id,created_at:row.created_at}));
      if(notifications.length){
        try{await upsertChunks('ihos_notifications',notifications)}catch(e:any){setNotice(`پیام ارسال شد اما ایجاد اعلان ناموفق بود: ${e.message}`);return}
      }
      setNotice(`پیام ارسال شد${notifications.length?` و برای ${fa(notifications.length)} نفر اعلان ثبت شد`:''}.`);
    }catch(e:any){setMessages(list=>list.filter(x=>x.id!==row.id));setBody(row.body);setNotice(`ارسال پیام ناموفق بود: ${e.message}`)}finally{setBusy(false)}
  }
  return <div className="v17Module messageCenterV17 redesignedMessagesV19"><div className="v17Hero"><div><span>INTERNAL COLLABORATION</span><div className="titleWithGuideV19"><h2>پیام‌رسان داخلی تیم</h2><GuideHint topic="messages"/></div><p>هر کانال گفت‌وگوی مستقل دارد؛ پیام‌های سازمان، تیم و افراد دیگر با هم مخلوط نمی‌شوند.</p></div><div className="messageStatusV19"><MessageCircle/><b>{fa(accessible.length)}</b><span>پیام قابل مشاهده</span></div></div><div className="v19MessengerShell"><aside className="v19ConversationRail"><div className="v19MessageSearch"><Search/><input value={query} onChange={e=>setQuery(e.target.value)} placeholder="جستجو در گفت‌وگوی باز..."/></div><section><h3>کانال‌ها</h3><button className={channel.type==='all'?'active':''} onClick={()=>setChannel({type:'all',id:'all'})}><span className="v19ChannelIcon org"><Building2/></span><div><b>کل سازمان</b><small>{lastFor('all','all')?.body||'کانال اطلاع‌رسانی عمومی'}</small></div><Hash/></button>{me.team&&<button className={channel.type==='team'&&channel.id===me.team?'active':''} onClick={()=>setChannel({type:'team',id:me.team})}><span className="v19ChannelIcon team"><Users2/></span><div><b>{me.team}</b><small>{lastFor('team',me.team)?.body||'گفت‌وگوی تیم شما'}</small></div><Hash/></button>}</section><section className="v19DirectList"><h3>پیام مستقیم <span>{fa(activeUsers.length)}</span></h3>{activeUsers.map((u:any)=>{const last=lastFor('user',u.id);return <button className={channel.type==='user'&&channel.id===u.id?'active':''} key={u.id} onClick={()=>setChannel({type:'user',id:u.id})}><span className="v19Avatar">{u.full_name.slice(0,1)}</span><div><b>{u.full_name}</b><small>{last?.body||u.team||u.role||'شروع گفت‌وگو'}</small></div><i className={u.is_active?'online':''}/></button>})}</section></aside><main className="v19ChatPane"><header className="v19ChatHeader"><div className="v19ChannelIdentity"><span>{channel.type==='all'?<Building2/>:channel.type==='team'?<Users2/>:<AtSign/>}</span><div><h3>{channelTitle}</h3><p>{channel.type==='all'?'پیام برای همه اعضای سازمان':channel.type==='team'?`کانال تیم ${channelTitle}`:`گفت‌وگوی مستقیم با ${channelTitle}`}</p></div></div><GuideHint topic="messages"/></header>{notice&&<div className="v19MessageNotice">{notice}</div>}<div className="v19MessageTimeline">{visible.map(m=>{const parent=parentMap.get(m.parent_id);return <article key={m.id} className={m.sender_id===me.id?'mine':''}><div className="v19MessageAvatar">{m.sender_name?.slice(0,1)||'ک'}</div><div className="v19Bubble"><header><b>{m.sender_name}</b>{m.is_important&&<Star/>}<time>{new Date(m.created_at).toLocaleString('fa-IR')}</time></header>{parent&&<div className="v19Quoted"><b>{parent.sender_name}</b><span>{parent.body}</span></div>}<p>{m.body}</p><footer>{m.hotel_title&&<span><Hotel/> {m.hotel_title}</span>}<button onClick={()=>setReplyTo(m)}>پاسخ</button></footer></div></article>})}{!visible.length&&<div className="v19NoMessages"><MessageCircle/><h3>هنوز پیامی نیست</h3><p>اولین پیام این گفت‌وگو را بنویسید.</p></div>}<div ref={bottomRef}/></div><footer className="v19ComposerWrap">{replyTo&&<div className="v19ReplyPreview"><div><span>پاسخ به {replyTo.sender_name}</span><p>{replyTo.body}</p></div><button aria-label="لغو پاسخ" onClick={()=>setReplyTo(null)}><X/></button></div>}<div className="v19ComposerMeta"><select value={hotelId} onChange={e=>setHotelId(e.target.value)}><option value="">بدون اتصال به هتل</option>{hotels.slice(0,1000).map((h:any)=><option key={h.id} value={h.id}>{h.title}</option>)}</select><button type="button" className={important?'active':''} onClick={()=>setImportant(!important)}><Star/> {important?'مهم':'علامت‌گذاری مهم'}</button></div><div className="v19Composer"><textarea value={body} onChange={e=>setBody(e.target.value)} onKeyDown={e=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();void send()}}} placeholder={`پیام به ${channelTitle}...`}/><button className="btn primary" disabled={!body.trim()||busy} onClick={send}><Send/> {busy?'در حال ارسال':'ارسال'}</button></div><small>Enter برای ارسال · Shift+Enter برای خط جدید</small></footer></main></div></div>
}

export function CalendarPlusV17({tasks=[],events=[],reminders=[],users=[],hotels=[],add,edit,remove}:any){
  const [mode,setMode]=useState<'month'|'week'|'agenda'>('month'),[cursor,setCursor]=useState(new Date()),[q,setQ]=useState(''),[owner,setOwner]=useState('all'),[kind,setKind]=useState('all');
  const cursorPersian=persianParts(cursor);
  const firstOfMonth=useMemo(()=>{let first=new Date(cursor);for(let i=0;i<32&&persianParts(first).day!==1;i++)first=addDays(first,-1);return first},[cursor]);
  const yearDates=useMemo(()=>{const dates:Date[]=[];const start=new Date(cursorPersian.year+621,2,1);for(let i=0;i<390;i++){const date=addDays(start,i);if(persianParts(date).year===cursorPersian.year)dates.push(date)}return dates},[cursorPersian.year]);
  const occasions=useMemo(()=>{
    const definitions=[...SOLAR_OCCASIONS,...(cursorPersian.year===1405?OFFICIAL_HOLIDAYS_1405:[])];
    return definitions.map((occasion,index)=>{const date=yearDates.find(candidate=>{const parts=persianParts(candidate);return parts.month===occasion.month&&parts.day===occasion.day});return date?{id:`occasion-${cursorPersian.year}-${occasion.month}-${occasion.day}-${index}`,date:localIso(date),title:occasion.title,type:occasion.holiday?'تعطیل رسمی':'مناسبت',kindKey:occasion.holiday?'holiday':'occasion',owner:'',hotel:'',source:null,holiday:!!occasion.holiday}:null}).filter(Boolean) as any[];
  },[cursorPersian.year,yearDates]);
  const items=useMemo(()=>[
    ...tasks.filter((t:any)=>t.deadline).map((t:any)=>({id:`task-${t.id}`,date:t.deadline,title:t.title,type:'تسک',kindKey:'task',owner:t.assigned_to,hotel:t.hotel_title,source:t})),
    ...events.map((e:any)=>({id:`event-${e.id}`,date:e.start_date,title:e.title,type:'رویداد',kindKey:'event',owner:e.user_id,hotel:hotels.find((h:any)=>h.id===e.hotel_id)?.title,source:e})),
    ...reminders.map((r:any)=>({id:`rem-${r.id}`,date:String(r.notify_at).slice(0,10),title:r.title,type:'یادآور',kindKey:'reminder',owner:r.user_id,hotel:'',source:r})),
    ...occasions
  ].filter(x=>(owner==='all'||!x.owner||x.owner===owner)&&(kind==='all'||x.type===kind)&&(!q||norm(`${x.title} ${x.hotel}`).includes(norm(q)))),[tasks,events,reminders,occasions,owner,kind,q,hotels]);
  const monthDates=useMemo(()=>{const out:Date[]=[];for(let i=0;i<32;i++){const date=addDays(firstOfMonth,i),parts=persianParts(date);if(parts.year!==cursorPersian.year||parts.month!==cursorPersian.month)break;out.push(date)}return out},[firstOfMonth,cursorPersian.year,cursorPersian.month]);
  const offset=(firstOfMonth.getDay()+1)%7;const days=Array.from({length:offset+monthDates.length},(_,i)=>i<offset?null:monthDates[i-offset]);
  function jump(delta:number){if(mode==='week'){setCursor(addDays(cursor,delta*7));return}setCursor(delta<0?addDays(firstOfMonth,-1):addDays(firstOfMonth,35))}
  const weekStart=addDays(cursor,-((cursor.getDay()+1)%7));const weekDays=Array.from({length:7},(_,i)=>addDays(weekStart,i));
  const list=mode==='week'?weekDays:days.filter(Boolean) as Date[];
  return <div className="v17Module jalaliCalendarV22"><div className="v17Hero"><div><span>PERSIAN OPERATIONS CALENDAR</span><h2>تقویم عملیاتی شمسی</h2><p>تسک، یادآور، رویداد، مناسبت‌های ملی و تعطیلات رسمی ۱۴۰۵ در یک نمای واحد.</p></div><div className="v17HeroActions"><button className="btn ghost" onClick={()=>setCursor(new Date())}>امروز</button><button className="btn primary" onClick={add}><Plus/> رویداد جدید</button></div></div><div className="v17CalendarToolbar"><div className="v17Seg" role="group" aria-label="نوع نمایش تقویم"><button aria-pressed={mode==='month'} className={mode==='month'?'active':''} onClick={()=>setMode('month')}>ماه</button><button aria-pressed={mode==='week'} className={mode==='week'?'active':''} onClick={()=>setMode('week')}>هفته</button><button aria-pressed={mode==='agenda'} className={mode==='agenda'?'active':''} onClick={()=>setMode('agenda')}>فهرست</button></div><div className="v17Search"><Search aria-hidden="true"/><input aria-label="جستجو در برنامه عملیاتی" value={q} onChange={e=>setQ(e.target.value)} placeholder="جستجوی برنامه و مناسبت..."/></div><select aria-label="فیلتر کارشناس" value={owner} onChange={e=>setOwner(e.target.value)}><option value="all">همه کارشناسان</option>{users.map((u:any)=><option key={u.id} value={u.id}>{u.full_name}</option>)}</select><select aria-label="فیلتر نوع برنامه" value={kind} onChange={e=>setKind(e.target.value)}><option value="all">همه انواع</option><option>تسک</option><option>رویداد</option><option>یادآور</option><option>تعطیل رسمی</option><option>مناسبت</option></select><button className="iconBtn" aria-label={mode==='week'?'هفته قبل':'ماه قبل'} onClick={()=>jump(-1)}><ChevronRight/></button><b aria-live="polite">{persianMonthFormatter.format(cursor)}</b><button className="iconBtn" aria-label={mode==='week'?'هفته بعد':'ماه بعد'} onClick={()=>jump(1)}><ChevronLeft/></button></div><div className="calendarLegendV22"><span><i className="holiday"/> تعطیل رسمی</span><span><i className="occasion"/> مناسبت ملی</span><span><i className="operation"/> برنامه عملیاتی</span>{cursorPersian.year!==1405&&<em>تعطیلات قمری فقط برای سال ۱۴۰۵ ثبت شده‌اند.</em>}</div>{mode==='agenda'?<div className="v17Agenda">{[...items].sort((a,b)=>a.date.localeCompare(b.date)).map(i=><article key={i.id} className={i.holiday?'holidayAgendaV22':''}><time dateTime={i.date}>{new Date(`${i.date}T12:00:00`).toLocaleDateString('fa-IR-u-ca-persian')}</time><div><b>{i.title}</b><small>{i.type}{i.hotel?` · ${i.hotel}`:''}</small></div>{i.type==='رویداد'&&<><button className="iconBtn" aria-label={`ویرایش رویداد ${i.title}`} onClick={()=>edit(i.source)}><Edit3/></button><button className="iconBtn dangerBtn" aria-label={`حذف رویداد ${i.title}`} onClick={()=>remove(i.source.id)}><Trash2/></button></>}</article>)}</div>:<div className={mode==='month'?'v17MonthGrid':'v17WeekGrid'}>{list.map((d:any,i)=>{if(!d)return <div className="v17EmptyDay" key={`e-${i}`}/>;const iso=localIso(d),dayItems=items.filter(x=>x.date===iso),parts=persianParts(d),isToday=iso===localIso(new Date()),hasHoliday=dayItems.some(x=>x.holiday);return <section key={iso} className={`${isToday?'todayV22 ':''}${hasHoliday?'holidayDayV22':''}`}><header><b>{d.toLocaleDateString('fa-IR',{weekday:'short'})}</b><span>{fa(parts.day)}</span></header>{dayItems.slice(0,5).map(x=><article key={x.id} className={`kind-${x.kindKey}`} title={x.title}><i/><span>{x.title}</span></article>)}{dayItems.length>5&&<small>+{fa(dayItems.length-5)} مورد</small>}</section>})}</div>}<footer className="calendarSourceV22">{PERSIAN_MONTHS[cursorPersian.month-1]} {fa(cursorPersian.year)} · مناسبت‌های شمسی هر سال و تعطیلات رسمی/قمری سال ۱۴۰۵</footer></div>
}

export function FinancialContractsV17({hotels=[]}:any){
  const [profiles,setProfiles]=useState<any[]>([]),[q,setQ]=useState(''),[riskOnly,setRiskOnly]=useState(false),[financialCategory,setFinancialCategory]=useState('all'),[editing,setEditing]=useState<any>(null);
  const drawerRef=useRef<HTMLElement>(null);
  async function load(){try{setProfiles(await loadAll('ihos_hotel_financial_profiles','*'))}catch{}}useEffect(()=>{void load()},[]);
  useEffect(()=>{
    if(!editing)return;
    const previous=document.activeElement as HTMLElement|null;
    const bodyOverflow=document.body.style.overflow;
    document.body.style.overflow='hidden';
    drawerRef.current?.focus();
    const onKeyDown=(event:KeyboardEvent)=>{if(event.key==='Escape')setEditing(null)};
    document.addEventListener('keydown',onKeyDown);
    return()=>{document.body.style.overflow=bodyOverflow;document.removeEventListener('keydown',onKeyDown);previous?.focus()};
  },[editing]);
  const pMap=useMemo(()=>new Map(profiles.map(p=>[p.hotel_id,p])),[profiles]);
  function predict(h:any,p:any){const settlement=norm(`${p?.settlement_model||''} ${p?.contract_financial_type||''}`);if(settlement.includes('به محض')||settlement.includes('رزرو')&&settlement.includes('فوری'))return'F';const purchase=Number(p?.purchase_days??h.purchase_period??0),payment=Number(p?.payment_days??h.payment_period??0),effective=purchase/2+payment;return effective>=25?'A+':effective>=18?'A':effective>=15?'A-':effective>=10?'B+':effective>=7?'B':effective>0?'B-':'D'}
  const validFinancialLevels=new Set(['A+','A','A-','B+','B','B-','D','F']);
  const baseRows=hotels.filter(isSellable).map((h:any)=>{const p=pMap.get(h.id)||{};const predicted=validFinancialLevels.has(p.predicted_category)?p.predicted_category:predict(h,p);const effectiveDays=Number(p.purchase_days??h.purchase_period??0)/2+Number(p.payment_days??h.payment_period??0);return{...h,financial:p,predicted,effectiveDays,risk:['B-','D','F'].includes(predicted)}}).filter((h:any)=>(!riskOnly||h.risk)&&(!q||norm(`${h.title} ${h.hotel_code} ${h.city} ${h.predicted}`).includes(norm(q))));
  const rows=baseRows.filter((h:any)=>financialCategory==='all'||h.predicted===financialCategory).sort((a:any,b:any)=>a.predicted.localeCompare(b.predicted,'fa')||String(a.title).localeCompare(String(b.title),'fa'));
  async function save(){const row={...editing,id:editing.id||`financial-${editing.hotel_id}`,updated_at:nowIso(),created_at:editing.created_at||nowIso()};await upsertChunks('ihos_hotel_financial_profiles',[row]);setEditing(null);await load()}
  const chart=Object.entries(baseRows.reduce((a:any,h:any)=>{a[h.predicted]=(a[h.predicted]||0)+1;return a},{})).map(([name,count])=>({name,count}));
  return <div className="v17Module"><div className="v17Hero"><div><span>FINANCIAL CONTRACT INTELLIGENCE</span><h2>قرارداد مالی و الگوی پرداخت هتل‌ها</h2><p>سطح کش‌فلو براساس نصف دوره خرید به‌علاوه دوره پرداخت محاسبه می‌شود؛ پرداخت در لحظه رزرو سطح F است.</p></div><div className="v17HeroMetric"><WalletCards/><b>{fa(rows.filter((r:any)=>r.risk).length)}</b><span>سطح B-، D یا F</span></div></div><div className="v17ChartPanel interactiveFinancialChartV22" role="region" aria-label={`نمودار تعاملی توزیع مالی هتل‌ها؛ ${chart.map(x=>`${x.name}: ${x.count}`).join('، ')}`}><div><h3>توزیع سطح کش‌فلو A+ تا F</h3><p>روی هر ستون کلیک کن تا فقط هتل‌های همان سطح نمایش داده شوند.</p>{financialCategory!=='all'&&<button className="btn ghost" onClick={()=>setFinancialCategory('all')}><X/> حذف فیلتر «{financialCategory}»</button>}</div><ResponsiveContainer width="100%" height={220}><BarChart data={chart} onClick={(state:any)=>{if(state?.activeLabel)setFinancialCategory(String(state.activeLabel))}}><CartesianGrid strokeDasharray="3 3" vertical={false}/><XAxis dataKey="name"/><YAxis allowDecimals={false}/><Tooltip/><Bar dataKey="count" name="هتل" fill="var(--color-primary)" radius={[8,8,0,0]} className="financialBarV22"/></BarChart></ResponsiveContainer></div><div className="v17Toolbar"><div className="v17Search"><Search aria-hidden="true"/><input aria-label="جستجوی پروفایل مالی هتل" value={q} onChange={e=>setQ(e.target.value)} placeholder="جستجوی هتل یا سطح مالی..."/></div><label className="v17Check"><input type="checkbox" checked={riskOnly} onChange={e=>setRiskOnly(e.target.checked)}/> فقط سطح B-، D و F</label>{financialCategory!=='all'&&<span className="financialFilterV22">{fa(rows.length)} هتل در سطح {financialCategory}</span>}</div><div className="v17DataTable financialTableV17"><div className="v17DataHead"><span>هتل</span><span>نوع قرارداد</span><span>خرید / پرداخت</span><span>مدل تسویه</span><span>سطح کش‌فلو</span><span/></div>{rows.slice(0,300).map((h:any)=><article key={h.id}><div><b>{h.title}</b><small>{h.hotel_code||'بدون کد'} · {h.city||'بدون شهر'}</small></div><span>{h.financial.contract_financial_type||h.hotel_category||'تعریف نشده'}</span><span>{h.financial.purchase_days??h.purchase_period??0} / {h.financial.payment_days??h.payment_period??0} · مؤثر {h.effectiveDays}</span><span>{h.financial.settlement_model||'تسویه دوره‌ای'}</span><span className={h.risk?'v17Danger':'v17Online'}>{h.predicted}</span><button className="iconBtn" aria-label={`ویرایش پروفایل مالی ${h.title}`} onClick={()=>setEditing({hotel_id:h.id,hotel_title:h.title,contract_financial_type:h.financial.contract_financial_type||'',settlement_model:h.financial.settlement_model||'',purchase_days:h.financial.purchase_days??h.purchase_period??0,payment_days:h.financial.payment_days??h.payment_period??0,commission_percent:h.financial.commission_percent||0,credit_limit:h.financial.credit_limit||0,predicted_category:h.financial.predicted_category||h.predicted,notes:h.financial.notes||'',...h.financial})}><Edit3/></button></article>)}</div>{editing&&<div className="v17DrawerBackdrop" onClick={()=>setEditing(null)}><aside ref={drawerRef} tabIndex={-1} className="v17Drawer" role="dialog" aria-modal="true" aria-label={`ویرایش پروفایل مالی ${editing.hotel_title}`} onClick={e=>e.stopPropagation()}><header><div><span>پروفایل مالی</span><h3>{editing.hotel_title}</h3></div><button aria-label="بستن پروفایل مالی" onClick={()=>setEditing(null)}><X/></button></header><div className="v17FormGrid"><label>نوع قرارداد مالی<input value={editing.contract_financial_type||''} onChange={e=>setEditing({...editing,contract_financial_type:e.target.value})}/></label><label>مدل تسویه<select value={editing.settlement_model||''} onChange={e=>setEditing({...editing,settlement_model:e.target.value})}><option>تسویه فوری</option><option>به محض ثبت رزرو</option><option>تسویه هفتگی</option><option>تسویه دوره‌ای</option><option>اعتباری</option><option>تضمینی</option></select></label><label>دوره خرید (روز)<input type="number" min="0" inputMode="numeric" value={editing.purchase_days||0} onChange={e=>setEditing({...editing,purchase_days:+e.target.value})}/></label><label>دوره پرداخت (روز)<input type="number" min="0" inputMode="numeric" value={editing.payment_days||0} onChange={e=>setEditing({...editing,payment_days:+e.target.value})}/></label><label>درصد کمیسیون<input type="number" min="0" max="100" inputMode="decimal" value={editing.commission_percent||0} onChange={e=>setEditing({...editing,commission_percent:+e.target.value})}/></label><label>سقف اعتبار<input type="number" min="0" inputMode="numeric" value={editing.credit_limit||0} onChange={e=>setEditing({...editing,credit_limit:+e.target.value})}/></label><label>دسته نهایی<select value={editing.predicted_category||''} onChange={e=>setEditing({...editing,predicted_category:e.target.value})}>{['A+','A','A-','B+','B','B-','D','F'].map(level=><option key={level}>{level}</option>)}</select></label><label className="full">توضیحات<textarea value={editing.notes||''} onChange={e=>setEditing({...editing,notes:e.target.value})}/></label></div><button className="btn primary full" onClick={save}><Check/> ذخیره پروفایل مالی</button></aside></div>}</div>
}

export function TeamCoverageV17({users=[],tasks=[],hotels:seedHotels=[]}:any){
  const provinces=[
    ['Ardebil','اردبیل'],['Esfahan','اصفهان'],['Alborz','البرز'],['Ilam','ایلام'],['East-Azarbaijan','آذربایجان شرقی'],['West-Azarbaijan','آذربایجان غربی'],['Bushehr','بوشهر'],['Tehran','تهران'],['Chahar-Mahall-and-Bakhtiari','چهارمحال و بختیاری'],['South-Khorasan','خراسان جنوبی'],['Razavi-Khorasan','خراسان رضوی'],['North-Khorasan','خراسان شمالی'],['Khuzestan','خوزستان'],['Zanjan','زنجان'],['Semnan','سمنان'],['Sistan-and-Baluchestan','سیستان و بلوچستان'],['Fars','فارس'],['Qazvin','قزوین'],['Qom','قم'],['Kordestan','کردستان'],['Kerman','کرمان'],['Kohgiluyeh-and-Buyer-Ahmad','کهگیلویه و بویراحمد'],['Kermanshah','کرمانشاه'],['Golestan','گلستان'],['Gilan','گیلان'],['Lorestan','لرستان'],['Mazandaran','مازندران'],['Markazi','مرکزی'],['Hormozgan','هرمزگان'],['Hamadan','همدان'],['Yazd','یزد']
  ];
  const regions=[
    {id:'central',title:'مرکز',provinces:['تهران','البرز','قم','مرکزی','اصفهان','یزد','سمنان','قزوین']},
    {id:'east-south',title:'شرق و جنوب',provinces:['خراسان رضوی','خراسان جنوبی','خراسان شمالی','کرمان','سیستان و بلوچستان','هرمزگان','فارس','بوشهر','خوزستان','کهگیلویه و بویراحمد','چهارمحال و بختیاری']},
    {id:'north-west',title:'شمال و غرب',provinces:['گیلان','مازندران','گلستان','آذربایجان شرقی','آذربایجان غربی','اردبیل','زنجان','کردستان','کرمانشاه','همدان','لرستان','ایلام']}
  ];
  const [hotels,setHotels]=useState<any[]>([]),[assignments,setAssignments]=useState<any[]>([]),[selectedProvince,setSelectedProvince]=useState('تهران'),[hoveredProvince,setHoveredProvince]=useState(''),[loading,setLoading]=useState(true),[notice,setNotice]=useState('');
  useEffect(()=>{(async()=>{setLoading(true);const result=await Promise.allSettled([loadAll('ihos_hotels','*'),loadAll('ihos_hotel_assignments','*')]);setHotels(result[0].status==='fulfilled'?result[0].value:[]);setAssignments(result[1].status==='fulfilled'?result[1].value:[]);setNotice(result.every(x=>x.status==='fulfilled')?'نقشه از هتل‌ها و تخصیص‌های واقعی Supabase ساخته شد.':'برخی داده‌های پوشش در دسترس نبود و برای جلوگیری از پوشش نادرست، آن منبع خالی نمایش داده شد.');setLoading(false)})()},[]);
  const provinceOf=(h:any)=>{const compact=(v:any)=>norm(v).replace(/^استان\s*/,'').replace(/[\s_-]+/g,'');const key=compact(h.province);return provinces.find(([id,faName])=>key===compact(id)||key===compact(faName))?.[1]||'نامشخص'};
  const unmappedHotelRows=hotels.filter(h=>provinceOf(h)==='نامشخص');
  const mappedHotelCount=hotels.length-unmappedHotelRows.length;
  const mapData=useMemo(()=>Object.fromEntries(provinces.map(([key,faName])=>[key,hotels.filter(h=>provinceOf(h)===faName).length])),[hotels]);
  const maxProvinceHotels=Math.max(1,...Object.values(mapData).map(Number));
  const regionData=useMemo(()=>regions.map(region=>{const regionHotels=hotels.filter(h=>region.provinces.includes(provinceOf(h)));const ids=new Set(regionHotels.map(h=>h.id));const assignmentIds=new Set(assignments.filter(a=>a.active!==false&&ids.has(a.hotel_id)).map(a=>a.user_id));const members=users.filter((u:any)=>u.is_active&&(assignmentIds.has(u.id)||norm(u.zone).includes(norm(region.title))||norm(u.team).includes(norm(region.title))||region.provinces.some(p=>norm(u.zone).includes(norm(p)))));const open=tasks.filter((t:any)=>ids.has(t.hotel_id)&&!['انجام شد','بسته شده','تایید شده'].includes(t.status));return{...region,hotels:regionHotels,members,open}}),[hotels,assignments,users,tasks]);
  const selectedHotels=hotels.filter(h=>provinceOf(h)===selectedProvince);const selectedIds=new Set(selectedHotels.map(h=>h.id));const selectedAssignments=assignments.filter(a=>a.active!==false&&selectedIds.has(a.hotel_id));const selectedUserIds=new Set(selectedAssignments.map(a=>a.user_id));const selectedRegion=regions.find(r=>r.provinces.includes(selectedProvince));const selectedMembers=users.filter((u:any)=>u.is_active&&(selectedUserIds.has(u.id)||selectedRegion&&[norm(u.zone),norm(u.team)].some(v=>v.includes(norm(selectedRegion.title)))));const selectedTasks=tasks.filter((t:any)=>selectedIds.has(t.hotel_id)&&!['انجام شد','بسته شده','تایید شده'].includes(t.status));
  const coveredIds=new Set(regionData.flatMap(r=>r.members.map((u:any)=>u.id)));const unmapped=users.filter((u:any)=>u.is_active&&!coveredIds.has(u.id));
  return <div className="v17Module accurateCoverageV19"><div className="v17Hero"><div><span>REAL PROVINCE COVERAGE</span><div className="titleWithGuideV19"><h2>نقشه پوشش کارشناسان و هتل‌ها</h2><GuideHint topic="team"/></div><p>نقشه واقعی ۳۱ استان؛ شدت رنگ براساس تعداد هتل ثبت‌شده و جزئیات پوشش براساس تخصیص فعال کارشناسان است.</p></div><div className="v17HeroMetric"><MapIcon/><b>{fa(mappedHotelCount)}</b><span>هتل با استان معتبر</span></div></div><div className="coverageSourceV19"><Database/><span>{loading?'در حال دریافت داده کامل...':`${notice}${unmappedHotelRows.length?` · ${fa(unmappedHotelRows.length)} هتل فاقد استان معتبر است.`:''}`}</span>{loading&&<RefreshCcw className="spin"/>}</div><div className="v17MapLayout"><section className="v17IranMap realIranMapV19"><div className="iranMapCanvasV19">{hoveredProvince&&<div className="iranMapTooltipV19"><b>{hoveredProvince}</b><span>{fa(hotels.filter(h=>provinceOf(h)===hoveredProvince).length)} هتل</span></div>}<svg viewBox={iranMap.viewBox} role="img" aria-label="نقشه استان‌های ایران">{iranMap.locations.map(location=>{const faName=provinces.find(([id])=>id===location.id)?.[1]||location.name;const count=Number(mapData[location.id]||0);const alpha=.18+.82*(count/maxProvinceHotels);return <path key={location.id} d={location.path} tabIndex={0} aria-label={`${faName}: ${fa(count)} هتل`} className={selectedProvince===faName?'selected':''} style={{fill:selectedProvince===faName?'#14b8a6':count?`rgba(37,99,235,${alpha})`:'var(--surface-2)'}} onMouseEnter={()=>setHoveredProvince(faName)} onMouseLeave={()=>setHoveredProvince('')} onFocus={()=>setHoveredProvince(faName)} onBlur={()=>setHoveredProvince('')} onClick={()=>setSelectedProvince(faName)} onKeyDown={e=>{if(e.key==='Enter'||e.key===' '){e.preventDefault();setSelectedProvince(faName)}}}><title>{faName}: {fa(count)} هتل</title></path>})}</svg></div><div className="v17MapLegend"><span><i/> شدت رنگ: تعداد هتل ثبت‌شده</span><span>برای مشاهده پوشش، روی استان کلیک کنید.</span></div></section><section className="v17RegionList coverageDetailsV19"><article className="selectedProvinceV19"><header><div><MapPin/><h3>{selectedProvince}</h3></div><b>{selectedRegion?.title||'منطقه نامشخص'}</b></header><div className="provinceMetricsV19"><span><b>{fa(selectedHotels.length)}</b> هتل</span><span><b>{fa(selectedTasks.length)}</b> تسک باز</span><span><b>{fa(selectedMembers.length)}</b> کارشناس</span></div><div className="v17AvatarStack">{selectedMembers.slice(0,10).map((u:any)=><span title={u.full_name} key={u.id}>{u.full_name.slice(0,1)}</span>)}</div><p>{selectedMembers.length?selectedMembers.map((u:any)=>u.full_name).join('، '):'برای این استان کارشناس مستقیم یا منطقه‌ای پیدا نشد.'}</p><small>{fa(selectedAssignments.length)} تخصیص فعال در ihos_hotel_assignments</small></article>{regionData.map(region=><article key={region.id}><header><div><Users2/><h3>{region.title}</h3></div><b>{fa(region.open.length)} تسک باز</b></header><div className="regionMetricsV19"><span>{fa(region.hotels.length)} هتل</span><span>{fa(region.members.length)} کارشناس</span><span>{fa(region.provinces.length)} استان</span></div><p>{region.members.length?region.members.map((u:any)=>u.full_name).join('، '):'پوشش کارشناسی ثبت نشده است.'}</p></article>)}{unmappedHotelRows.length>0&&<article className="warning"><header><div><Hotel/><h3>هتل بدون استان معتبر</h3></div><b>{fa(unmappedHotelRows.length)}</b></header><p>{unmappedHotelRows.slice(0,12).map(h=>h.title).join('، ')}{unmappedHotelRows.length>12?' و موارد دیگر':''}</p></article>}{unmapped.length>0&&<article className="warning"><header><div><Flag/><h3>کارشناس بدون منطقه قابل تشخیص</h3></div><b>{fa(unmapped.length)}</b></header><p>{unmapped.map((u:any)=>u.full_name).join('، ')}</p></article>}</section></div></div>
}
